&Percentual = 100
&ProgressFin = serverNow()
do 'Atualiza'

Sub 'Atualiza'
	for each Order ProgressId
		where ProgressId = &ProgressId
		ProgressValue = &Percentual
		ProgressLogXml = &sdtEstoque.ToXml()
		ProgressFin = &ProgressFin
		ProgressIni = &Progressini
	When none
		new
			ProgressId = &ProgressId
			ProgressValue = &Percentual
			ProgressLogXml = &sdtEstoque.ToXml()
			ProgressFin = &ProgressFin
			ProgressIni = &Progressini
		Endnew
	endfor

	commit
EndSub


